const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

class ApiService {
  async request(endpoint, options = {}) {
    const url = `${API_BASE_URL}${endpoint}`;
    const config = {
      headers: {
        'Content-Type': 'application/json',
        ...options.headers,
      },
      ...options,
    };

    try {
      const response = await fetch(url, config);
      const data = await response.json();
      
      if (!response.ok) {
        throw new Error(data.error || `HTTP ${response.status}: ${data.message || 'API request failed'}`);
      }
      
      return data;
    } catch (error) {
      console.error('API Error:', error);
      throw error;
    }
  }

  async sendMessage(message, sessionId, fileContent = null) {
    return this.request('/chat', {
      method: 'POST',
      body: JSON.stringify({
        message,
        session_id: sessionId,
        file_content: fileContent
      }),
    });
  }

  async uploadFile(file, sessionId) {
    try {
      const formData = new FormData();
      formData.append('file', file);
      if (sessionId) {
        formData.append('session_id', sessionId);
      }

      // Use direct fetch for file upload (no JSON headers)
      const response = await fetch('/api/files/upload', {
        method: 'POST',
        body: formData,
      });

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({ error: 'Upload failed' }));
        throw new Error(errorData.error || `Upload failed with status ${response.status}`);
      }

      const data = await response.json();
      return data;
    } catch (error) {
      console.error('File Upload Error:', error);
      throw error;
    }
  }

  async createNewSession() {
    return this.request('/new-session', {
      method: 'POST',
    });
  }

  async clearSession(sessionId) {
    return this.request('/clear-session', {
      method: 'POST',
      body: JSON.stringify({
        session_id: sessionId,
      }),
    });
  }

  async checkHealth() {
    return this.request('/health');
  }

  async getFileFormats() {
    return this.request('/files/supported');
  }

  async testChat() {
    return this.request('/chat/test');
  }

  async testFileUpload() {
    return this.request('/files/test');
  }
}

export default new ApiService();
